import React, { useState } from 'react';
import { Handle, Position } from 'reactflow';

// InputNode: lets the user type a prompt
// Calls data.onChange on every keystroke to update parent state
function InputNode({ data }) {
  const [value, setValue] = useState('');

  const handleChange = (e) => {
    setValue(e.target.value);
    data.onChange(e.target.value);
  };

  return (
    <div className="custom-node input-node">
      <div className="node-header">📝 Prompt Input</div>
      <div className="node-body">
        <textarea
          className="node-textarea"
          value={value}
          onChange={handleChange}
          placeholder="Type your prompt here..."
          rows={5}
        />
      </div>
      {/* Source handle: connects to OutputNode */}
      <Handle type="source" position={Position.Right} id="out" />
    </div>
  );
}

export default InputNode;
